import { DatePipe, formatNumber } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
import { FreezingLoanApps } from "../../Models/Loan/FreezingLoanApplications";

@Component({
  selector: "app-unfreeze-loan-applications",
  templateUrl: "./unfreeze-loan-applications.page.html",
  styleUrls: ["./unfreeze-loan-applications.page.scss"],
})
export class UnfreezeLoanApplicationsPage implements OnInit {
  showLoader: boolean = false;
  details: boolean = false;

  sortingIconClass: string;
  sortingIconParam: string;

  freezingLoanApps: FreezingLoanApps[];
  filterFreezingApps: FreezingLoanApps[];

  page = 1; // the page we are viewing

  org_code: string;

  SearchForm: FormGroup = this.formBuilder.group({
    search_input: [""],
    branch_code: [""],
  });

  CurrentApplicationForm: FormGroup = this.formBuilder.group({
    clientName: [""],
    mobile: [""],
    docSuspendedNote: [""],
  });

  constructor(
    private env: EnvService,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private datePipe: DatePipe,
    private sortingService: sortingService,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    public pagingService: pagingService
  ) {}

  async ngOnInit() {
    await this.authService.getUserInfo().then((userInfo) => {
      this.org_code = userInfo.org_code;
    });
    this.getFreezedApplications();
  }

  getFreezedApplications() {
    this.showLoader = true;
    this.http
      .get<FreezingLoanApps[]>(
        this.env.API_URL + "api/LoanApplications/GetAllFreezedLoanApplications"
      )
      .subscribe({
        next: (data) => {
          this.freezingLoanApps = data;
          this.filterFreezingApps = this.freezingLoanApps;
          console.log(this.freezingLoanApps);
          this.showLoader = false;
        },
        error: (error) => {
          this.alertService.showAlertError(error.error, false);

          this.showLoader = false;
        },
      });
  }

  async enableLoanApp(freezingApp: FreezingLoanApps) {
    if (await this.alertService.SaveAlert()) {
      this.showLoader = true;
      // console.log("data", freezingApp);
      this.http
        .post(
          this.env.API_URL + `api/LoanApplications/UnFreezeLoanApplications`,
          {
            org_code: this.org_code,
            branch_code: freezingApp.branch_code,
            application_key: freezingApp.doc_key.toString(),
          }
        )
        .subscribe({
          next: (data) => {
            this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
            this.showLoader = false;
          },
          error: (error) => {
            this.alertService.showAlertError(error.error, false);

            this.showLoader = false;
          },
        });
    }
  }

  searchForUsers() {
    this.page = 1;
    let client_name = this.SearchForm.value.search_input;

    this.filterFreezingApps = this.freezingLoanApps.filter(
      (v) =>
        client_name == "" ||
        v.client_name.toLowerCase().match(client_name.toLowerCase())
    );
  }

  moreInfo(freezingApp: FreezingLoanApps) {
    this.details = true;
    this.CurrentApplicationForm.patchValue({
      clientName: freezingApp.client_name,
      mobile: freezingApp.mobile_1,
      docSuspendedNote: freezingApp.doc_suspended_note,
    });
  }

  changePage(newPage: number): void {
    this.page = newPage;
  }

  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }

  dateFormat(date) {
    return this.datePipe.transform(date, "yyyy-MM-dd");
  }

  NumberFormatStyle(number) {
    let result = formatNumber(Number(number), "en-US", "1.0");
    return result;
  }

  dismissModal() {
    this.details = false;
  }
}
